-decoration:none;font-weight:600}.table-name-link:hover{color:#389B5B;text-decoration:underline}.empty{padding:22px 10px;color:#6b7280;text-align:center}.action-icons{display:flex;gap:10px}.icon-btn svg{width:16px;height:16px;stroke:currentColor;fill:none;stroke-width:1.8}.icon-btn{color:#111827}.icon-btn.delete{color:#ef4444}.tag{display:inline-flex;padding:5px 10px;border-radius:999px;font-weight:600;font-size:.76rem}.ok{background:#dcfce7;color:#166534}.bottom{display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;margin-top:18px}.pager{color:#6b7280;font-size:.84rem}@media(max-width:1100px){.stepper{padding:14px}.step-list{grid-template-columns:repeat(3,minmax(0,1fr))}.step-label{max-width:none}}</style>
